using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Get the occurrences from the root component.
    Ptr occurrences = rootComp->occurrences();
    if (!occurrences)
        return false;

    // Build an array of occurrences because breaking a link will cause the
    // collection to be modified and causes a problem iterating over the colection.
    std::vector> occs;
    for (int i = 0; i count(); ++i)
    {
        if (Ptr occ = occurrences->item(i))
            occs.push_back(occ);
    }

    // Iterate through the top-level occurrences to see if any of them are external references.
    for (Ptr occ : occs)
    {
        if (occ->isReferencedComponent())
        {
            occ->breakLink();
        }
    }

    return true;
}
